inline bool VerifyMessagePayload(::flatbuffers::VerifierTemplate<B> &verifier, const void *obj, MessagePayload type) {
  switch (type) {
    case MessagePayload_NONE: {
      return true;
    }
    case MessagePayload_CommandMessage: {
      auto ptr = reinterpret_cast<const omnigpu::fbs::CommandMessage *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload_DataMessage: {
      auto ptr = reinterpret_cast<const omnigpu::fbs::DataMessage *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

template <bool B>
inline bool VerifyMessagePayloadVector(::flatbuffers::VerifierTemplate<B> &verifier, const ::flatbuffers::Vector<::flatbuffers::Offset<void>> *values, const ::flatbuffers::Vector<uint8_t> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (::flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyMessagePayload(
        verifier,  values->Get(i), types->GetEnum<MessagePayload>(i))) {
      return false;
    }
  }
  return true;
}

inline void *MessagePayloadUnion::UnPack(const void *obj, MessagePayload type, const ::flatbuffers::resolver_function_t *resolver) {
  (void)resolver;
  switch (type) {
    case MessagePayload_CommandMessage: {
      auto ptr = reinterpret_cast<const omnigpu::fbs::CommandMessage *>(obj);
      return ptr->UnPack(resolver);
    }
    case MessagePayload_DataMessage: {
      auto ptr = reinterpret_cast<const omnigpu::fbs::DataMessage *>(obj);
      return ptr->UnPack(resolver);
    }
    default: return nullptr;
  }
}

inline ::flatbuffers::Offset<void> MessagePayloadUnion::Pack(::flatbuffers::FlatBufferBuilder &_fbb, const ::flatbuffers::rehasher_function_t *_rehasher) const {
  (void)_rehasher;
  switch (type) {
    case MessagePayload_CommandMessage: {
      auto ptr = reinterpret_cast<const omnigpu::fbs::CommandMessageT *>(value);
      return CreateCommandMessage(_fbb, ptr, _rehasher).Union();
    }
    case MessagePayload_DataMessage: {
      auto ptr = reinterpret_cast<const omnigpu::fbs::DataMessageT *>(value);
      return CreateDataMessage(_fbb, ptr, _rehasher).Union();
    }
    default: return 0;
  }
}

inline MessagePayloadUnion::MessagePayloadUnion(const MessagePayloadUnion &u) : type(u.type), value(nullptr) {
  switch (type) {
    case MessagePayload_CommandMessage: {
      value = new omnigpu::fbs::CommandMessageT(*reinterpret_cast<omnigpu::fbs::CommandMessageT *>(u.value));
      break;
    }
    case MessagePayload_DataMessage: {
      value = new omnigpu::fbs::DataMessageT(*reinterpret_cast<omnigpu::fbs::DataMessageT *>(u.value));
      break;
    }
    default:
      break;
  }
}

inline void MessagePayloadUnion::Reset() {
  switch (type) {
    case MessagePayload_CommandMessage: {
      auto ptr = reinterpret_cast<omnigpu::fbs::CommandMessageT *>(value);
      delete ptr;
      break;
    }
    case MessagePayload_DataMessage: {
      auto ptr = reinterpret_cast<omnigpu::fbs::DataMessageT *>(value);
      delete ptr;
      break;
    }
    default: break;
  }
  value = nullptr;
  type = MessagePayload_NONE;
}

inline const omnigpu::fbs::Message *GetMessage(const void *buf) {
  return ::flatbuffers::GetRoot<omnigpu::fbs::Message>(buf);
}

inline const omnigpu::fbs::Message *GetSizePrefixedMessage(const void *buf) {
  return ::flatbuffers::GetSizePrefixedRoot<omnigpu::fbs::Message>(buf);
}

template <bool B = false>
inline bool VerifyMessageBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifyBuffer<omnigpu::fbs::Message>(nullptr);
}

template <bool B = false>
inline bool VerifySizePrefixedMessageBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifySizePrefixedBuffer<omnigpu::fbs::Message>(nullptr);
}

inline void FinishMessageBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<omnigpu::fbs::Message> root) {
  fbb.Finish(root);
}

inline void FinishSizePrefixedMessageBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<omnigpu::fbs::Message> root) {
  fbb.FinishSizePrefixed(root);
}

inline std::unique_ptr<omnigpu::fbs::MessageT> UnPackMessage(
    const void *buf,
    const ::flatbuffers::resolver_function_t *res = nullptr) {
  return std::unique_ptr<omnigpu::fbs::MessageT>(GetMessage(buf)->UnPack(res));
}

inline std::unique_ptr<omnigpu::fbs::MessageT> UnPackSizePrefixedMessage(
    const void *buf,
    const ::flatbuffers::resolver_function_t *res = nullptr) {
  return std::unique_ptr<omnigpu::fbs::MessageT>(GetSizePrefixedMessage(buf)->UnPack(res));
}

